import type { CommandHandler } from '@moneyworks/cli';

const myCommand: CommandHandler = async (client, args, options) => {
  if (options.debug) {
    console.log('[DEBUG] Starting my command');
  }

  // Command implementation
  const data = await client.smartExport('TaxRate');
  console.log(`Found ${data.length} records`);
};

export default myCommand;

interface GlobalOptions {
  config?: string;   // Path to config file
  debug?: boolean;   // Enable debug output
  timing?: boolean;  // Show timing information
}

// Accessing in command handler
if (options.debug) {
  console.log('[DEBUG] Debug mode enabled');
}

if (options.timing) {
  const start = Date.now();
  // ... operation ...
  console.log(`Timing: ${Date.now() - start}ms`);
}

interface ImportOptions extends GlobalOptions {
  file: string;           // Input file path (required)
  mode?: ImportMode;      // create, update, createOrUpdate
  workItOut?: boolean;    // Auto field resolution
  calculate?: string;     // Calculated fields
}

type ImportMode = 'create' | 'update' | 'createOrUpdate';

import { formatOutput } from '@moneyworks/cli/utils';

const data = [{ TaxCode: 'GST10', Rate1: 10 }];

// Format as compact
const compact = formatOutput(data, 'compact');
// [["GST10", 10]]

// Format with schema
const schema = formatOutput(data, 'schema');
// { schema: {...}, data: [...], metadata: {...} }

import { parseFilter } from '@moneyworks/cli/utils';

// Valid filters
parseFilter("Rate1 > 10");  // "Rate1 > 10"
parseFilter("Status='Active'");  // "Status='Active'"

// Handles edge cases
parseFilter("");  // undefined
parseFilter(" ");  // undefined

import { timing } from '@moneyworks/cli/utils';

// Time an operation
const data = await timing('Export', async () => {
  return await client.smartExport('TaxRate');
});
// Output: Timing: Export: 123ms

// Nested timing
const result = await timing('Total', async () => {
  await timing('Connect', () => client.connect());
  return await timing('Query', () => client.query());
});
// Output:
// Timing: Connect: 45ms
// Timing: Query: 78ms
// Timing: Total: 123ms
